const resp = $input.first().json;
const rows = resp.values || [];
if (rows.length < 2) return [{ json: { services: [] } }];
const headers = rows[0];
const services = rows.slice(1)
  .filter(row => row.length > 0 && row[0])
  .map(row => {
    const obj = {};
    headers.forEach((h, i) => { obj[h] = (row[i] || '').trim(); });
    return {
      slug:         obj.slug         || '',
      number:       obj.number       || '',
      card_eyebrow: obj.card_eyebrow || '',
      card_title:   obj.card_title   || '',
      card_desc:    obj.card_desc    || '',
      page_intro:   obj.page_intro   || '',
      item1_title:  obj.item1_title  || '',
      item1_desc:   obj.item1_desc   || '',
      item1_tag1:   obj.item1_tag1   || '',
      item1_tag2:   obj.item1_tag2   || '',
      item2_title:  obj.item2_title  || '',
      item2_desc:   obj.item2_desc   || '',
      item2_tag1:   obj.item2_tag1   || '',
      item2_tag2:   obj.item2_tag2   || '',
      item3_title:  obj.item3_title  || '',
      item3_desc:   obj.item3_desc   || '',
      item3_tag1:   obj.item3_tag1   || '',
      item3_tag2:   obj.item3_tag2   || '',
      callout_text: obj.callout_text || '',
      image_prompt: obj.image_prompt || ''
    };
  });
return [{ json: { services } }];
